1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Step = { op: "quote"; items: Item[] } | { op: "claim" };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const FIRST_INSURANCE_MULTIPLIER = 1.1;
15	const PROCESSING_FEE = 5;
16	
17	const ceilToWholeG = (amount: number): number =>
18	  Math.ceil(Math.round(amount * 100) / 100);
19	
20	const COMPONENT_BUNDLE_PRICE = 60;
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	const itemMultiplier = (item: Item): number => (item.cursed ? 1.5 : 1);
24	
25	const baseForGroup = (type: string, group: Item[]): number => {
26	  const unitPrice = BASE_PREMIUM[type] ?? 0;
27	  if (COMPONENT_TYPES.has(type)) {
28	    const bundles = Math.floor(group.length / 3);
29	    const bundleBase = bundles * COMPONENT_BUNDLE_PRICE;
30	    const singles = group.slice(bundles * 3);
31	    const singlesBase = singles.reduce((sum, item) => sum + unitPrice * itemMultiplier(item), 0);
32	    return bundleBase + singlesBase;
33	  }
34	  return group.reduce((sum, item) => sum + unitPrice * itemMultiplier(item), 0);
35	};
36	
37	const groupByType = (items: Item[]): Map<string, Item[]> => {
38	  const groups = new Map<string, Item[]>();
39	  for (const item of items) {
40	    const list = groups.get(item.type) ?? [];
41	    list.push(item);
42	    groups.set(item.type, list);
43	  }
44	  return groups;
45	};
46	
47	const quote = (items: Item[]): number => {
48	  const base = [...groupByType(items)].reduce(
49	    (sum, [type, group]) => sum + baseForGroup(type, group),
50	    0,
51	  );
52	  return ceilToWholeG(base * FIRST_INSURANCE_MULTIPLIER) + PROCESSING_FEE;
53	};
54	
55	const processStep = (step: Step): unknown =>
56	  step.op === "quote" ? { premium: quote(step.items) } : {};
57	
58	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
59	  results: scenario.steps.map(processStep),
60	});
